const input = $json.body ?? $json;
const required = ['client_id', 'workflow_name', 'feature_type'];
for (const field of required) {
  if (typeof input[field] !== 'string' || input[field].trim() === '') {
    throw new Error(`Missing required field: ${field}`);
  }
}
if (input.feature_type !== 'workflow_automation') {
  throw new Error('feature_type must be workflow_automation');
}
const sourceId = String(input.source_event_id ?? input.external_id ?? '');
if (!sourceId) throw new Error('Missing source_event_id or external_id');
const eventId = `${input.client_id}:lead:${sourceId}`;
return [{ json: { ...input, event_id: eventId, status: 'success', normalized_at: new Date().toISOString() } }];
